<?php require_once __DIR__.'/../includes/functions.php'; require_once __DIR__.'/../includes/db.php'; require_admin(); $pdo=db(); if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??null)){ if(($_POST['action']??'')==='delete'){ $pdo->prepare('DELETE FROM gallery_items WHERE id=?')->execute([(int)$_POST['id']]); } else { $data=[post_value('type')==='video'?'video':'image',post_value('title'),post_value('file_path'),post_value('description'),post_value('status')==='inactive'?'inactive':'active',(int)post_value('sort_order')]; if(!empty($_POST['id'])){ $data[]=(int)$_POST['id']; $pdo->prepare('UPDATE gallery_items SET type=?,title=?,file_path=?,description=?,status=?,sort_order=? WHERE id=?')->execute($data); } else { $pdo->prepare('INSERT INTO gallery_items (type,title,file_path,description,status,sort_order) VALUES (?,?,?,?,?,?)')->execute($data); } } redirect('gallery.php'); } include 'partials/header.php'; include 'partials/sidebar.php'; $rows=$pdo->query('SELECT * FROM gallery_items ORDER BY sort_order,id')->fetchAll(); ?><h2 class="mb-4 text-3xl font-black">Manage Gallery & Videos</h2><p class="mb-4 text-slate-600">Use image paths like <b>assets/images/kiwai.jpg</b> or video embed URLs such as YouTube embed links.</p><form method="post" class="mb-6 grid gap-3 rounded-2xl bg-white p-5 shadow md:grid-cols-2"><input type="hidden" name="csrf_token" value="<?=e(csrf_token())?>"><select name="type" class="rounded border p-3"><option value="image">image</option><option value="video">video</option></select><input name="title" required class="rounded border p-3" placeholder="Title"><input name="file_path" required class="rounded border p-3 md:col-span-2" placeholder="Image path or video embed URL"><input type="number" name="sort_order" value="0" class="rounded border p-3"><select name="status" class="rounded border p-3"><option value="active">active</option><option value="inactive">inactive</option></select><textarea name="description" class="rounded border p-3 md:col-span-2" placeholder="Caption / SEO description"></textarea><button class="rounded bg-slate-950 px-5 py-3 font-bold text-white md:col-span-2">Add Media</button></form><div class="grid gap-4"><?php foreach($rows as $r):?><form method="post" class="grid gap-2 rounded-2xl bg-white p-4 shadow md:grid-cols-5"><input type="hidden" name="csrf_token" value="<?=e(csrf_token())?>"><input type="hidden" name="id" value="<?=e($r['id'])?>"><select name="type" class="rounded border p-2"><option <?=$r['type']==='image'?'selected':''?>>image</option><option <?=$r['type']==='video'?'selected':''?>>video</option></select><input name="title" value="<?=e($r['title'])?>" class="rounded border p-2"><input name="file_path" value="<?=e($r['file_path'])?>" class="rounded border p-2 md:col-span-2"><input type="number" name="sort_order" value="<?=e($r['sort_order'])?>" class="rounded border p-2"><select name="status" class="rounded border p-2"><option <?=$r['status']==='active'?'selected':''?>>active</option><option <?=$r['status']==='inactive'?'selected':''?>>inactive</option></select><textarea name="description" class="rounded border p-2 md:col-span-4"><?=e($r['description'])?></textarea><button class="rounded bg-blue-950 px-4 py-2 font-bold text-white">Update</button><button name="action" value="delete" onclick="return confirm('Delete this media item?')" class="rounded bg-red-700 px-4 py-2 font-bold text-white">Remove</button></form><?php endforeach;?></div><?php include 'partials/footer.php'; ?>
